#include <iostream>
#include <vector>
#include <bitset>

vector<int> popcountDepth(vector<int>& nums, vector<vector<int>>& queries) {
    vector<int> answer(queries[0].size());
    int popcount = 0;
    int depth = 0;

    for (int i = 0; i < queries.size(); i++) {
        int l = queries[i][0], r = queries[i][1], k = queries[i][2], idx = queries[i][3];
        nums[idx] = popcount;
        while (depth < k) {
            popcount = 0;
            for (int j = l; j <= r; j++) {
                popcount += bitset<32>(nums[j]).count();
                depth++;
            }
        }
        answer[i] = depth;
    }
    return answer;
}
